import { Router } from "express";
import * as siteController from "../controllers/site.controller.js";
import { asyncHandler } from "../utils/asyncHandler.js";
import { requireAuth } from "../middleware/auth.js";
const router = Router();
router.use(requireAuth);
router.post("/", asyncHandler(siteController.createSite));
router.patch("/:siteId", asyncHandler(siteController.updateSite));
router.delete("/:siteId", asyncHandler(siteController.deleteSite));
export default router;
